import axios from "axios";

const TOKEN_KEY = "medcompare_token";
const SIGNUP_FLAG_KEY = "medcompare_signup_complete";

export const getAuthToken = () => localStorage.getItem(TOKEN_KEY);

export const isSignupComplete = () => localStorage.getItem(SIGNUP_FLAG_KEY) === "true";

export const setAuthToken = (token) => {
	localStorage.setItem(TOKEN_KEY, token);
};

export const setSignupComplete = () => {
	localStorage.setItem(SIGNUP_FLAG_KEY, "true");
};

export const clearSignupComplete = () => {
	localStorage.removeItem(SIGNUP_FLAG_KEY);
};

export const clearAuthToken = () => {
	localStorage.removeItem(TOKEN_KEY);
};

export const api = axios.create({
	baseURL: process.env.REACT_APP_API_BASE_URL || "/api",
});

api.interceptors.request.use((config) => {
	const token = getAuthToken();
	if (token) {
		config.headers.Authorization = `Token ${token}`;
	}
	return config;
});
